INSERT INTO knowledge_base (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('c++', 1, 'beginner', 1, 'Hello World 程序', '["程序结构","输出"]', '学习C++基本程序结构，包括main函数和cout输出。', '在C++中，每个程序都必须有一个main函数作为入口点。使用iostream库中的cout对象可以输出文本到控制台。\n示例程序展示了如何包含头文件、使用命名空间和定义main函数。', '["#include <iostream>\\nusing namespace std;\\n\\nint main() {\\n    cout << \\"Hello, World!\\" << endl;\\n    return 0;\\n}"]', '["Hello, World!"]'),
('c++', 2, 'beginner', 1, '变量声明与初始化', '["变量","基础"]', '学习C++中变量的声明和初始化方法。', '变量用于存储数据。声明变量时指定数据类型，如int、float等。初始化可以在声明时赋值。示例展示如何声明并输出变量值。', '["int x = 10;\\ncout << \\"The value of x is: \\" << x;"]', '["The value of x is: 10"]'),
('c++', 3, 'beginner', 1, '基本数据类型', '["数据类型","基础"]', '介绍C++中的基本数据类型及其使用。', 'C++提供了多种基本数据类型，包括整型(int)、浮点型(float, double)、字符型(char)和布尔型(bool)。每种类型有不同的存储大小和取值范围。', '["int a = 42;\\nfloat b = 3.14;\\nchar c = \\"C\\";\\nbool d = true;\\ncout << a << \\" \\" << b << \\" \\" << c << \\" \\" << d;"]', '["42 3.14 C 1"]'),
('c++', 4, 'beginner', 1, '基本输入输出', '["输入输出","基础"]', '学习使用cin和cout进行基本输入输出操作。', '在C++中，使用iostream库的cin对象进行输入，cout对象进行输出。示例展示如何从用户获取输入并输出结果。', '["#include <iostream>\\nusing namespace std;\\n\\nint main() {\\n    int number;\\n    cout << \\"Enter a number: \\";\\n    cin >> number;\\n    cout << \\"You entered: \\" << number;\\n    return 0;\\n}"]', '["Enter a number: 5\\nYou entered: 5"]'),
('c++', 5, 'beginner', 1, 'if条件语句', '["条件语句","控制流"]', '学习使用if语句进行条件判断。', 'if语句允许根据条件执行不同的代码块。语法：if (condition) { // code }。可以扩展为if-else和if-else if链。', '["int x = 10;\\nif (x > 5) {\\n    cout << \\"x is greater than 5\\";\\n} else {\\n    cout << \\"x is not greater than 5\\";\\n}"]', '["x is greater than 5"]');